// leanBench static site — list + detail views + charts.
//
// Data contract: `results/index.json` lists all runs grouped by machine;
// per-run detail comes from `results/<filename>.json`. The index is
// regenerated by scripts/build_index.py at deploy time (not committed).

const page = document.body.dataset.page
  || (location.pathname.endsWith("/run.html") ? "run"
      : "index");

// ---------- shared helpers --------------------------------------------------

const fmtNs = (ns) => {
  if (ns == null || Number.isNaN(ns)) return "—";
  if (ns < 10_000) return `${ns} ns`;
  if (ns < 10_000_000) return `${(ns / 1e3).toFixed(1)} µs`;
  if (ns < 10_000_000_000) return `${(ns / 1e6).toFixed(2)} ms`;
  return `${(ns / 1e9).toFixed(2)} s`;
};

const fmtBytes = (b) => {
  if (b == null) return "—";
  if (b < 1024) return `${b} B`;
  if (b < 1024 * 1024) return `${(b / 1024).toFixed(1)} KiB`;
  if (b < 1024 ** 3) return `${(b / 1024 ** 2).toFixed(1)} MiB`;
  return `${(b / 1024 ** 3).toFixed(2)} GiB`;
};

const fmtDate = (iso) => {
  if (!iso) return "—";
  try {
    const d = new Date(iso);
    return d.toISOString().replace("T", " ").slice(0, 16) + " UTC";
  } catch { return iso; }
};

// Compact, glanceable relative time for the "last updated" stat — avoids
// wrapping 20+ characters of ISO timestamp into the big stat cell.
const fmtRelative = (iso) => {
  if (!iso) return "—";
  try {
    const d = new Date(iso);
    const diffS = (d.getTime() - Date.now()) / 1000;
    const abs = Math.abs(diffS);
    const rtf = new Intl.RelativeTimeFormat("en", { numeric: "auto" });
    if (abs < 60) return rtf.format(Math.round(diffS), "second");
    if (abs < 3600) return rtf.format(Math.round(diffS / 60), "minute");
    if (abs < 86400) return rtf.format(Math.round(diffS / 3600), "hour");
    if (abs < 86400 * 30) return rtf.format(Math.round(diffS / 86400), "day");
    return d.toISOString().slice(0, 10);
  } catch { return iso; }
};

const el = (tag, attrs = {}, ...children) => {
  const n = document.createElement(tag);
  for (const [k, v] of Object.entries(attrs)) {
    if (k === "class") n.className = v;
    else if (k === "text") n.textContent = v;
    else if (k.startsWith("on")) n.addEventListener(k.slice(2), v);
    else n.setAttribute(k, v);
  }
  for (const c of children) {
    if (c == null) continue;
    n.appendChild(typeof c === "string" ? document.createTextNode(c) : c);
  }
  return n;
};

// Round `v` up to the next "nice" axis tick: 1/1.5/2/2.5/3/4/5/7.5/10
// times the appropriate power of ten. Used to give comparison charts a
// readable upper bound on the x-axis instead of `maxValue * 1.04`.
const niceCeil = (v) => {
  if (!(v > 0)) return 1;
  const exp = Math.pow(10, Math.floor(Math.log10(v)));
  const f = v / exp;
  const fractions = [1, 1.5, 2, 2.5, 3, 4, 5, 7.5, 10];
  return fractions.find((nf) => nf >= f) * exp;
};

// Colour palette for series — keeps machine lines visually distinct.
const PALETTE = [
  "#4a46d9", "#0891b2", "#16a34a", "#d97706",
  "#be185d", "#7c3aed", "#0369a1", "#ea580c",
];
const colorFor = (i) => PALETTE[i % PALETTE.length];

const chartTheme = () => {
  const dark = matchMedia("(prefers-color-scheme: dark)").matches;
  return {
    text: dark ? "#f0f0ea" : "#1a1a1a",
    grid: dark ? "#2a2a32" : "#e5e5e0",
  };
};

// Apply theme defaults to Chart.js globally.
(() => {
  if (typeof Chart === "undefined") return;
  const t = chartTheme();
  Chart.defaults.color = t.text;
  Chart.defaults.borderColor = t.grid;
  Chart.defaults.font.family = getComputedStyle(document.body)
    .getPropertyValue("--sans") || "-apple-system, sans-serif";
})();

// ---------- INDEX page ------------------------------------------------------

// Active (leansig, leanmultisig) SHA pair. Runs from other combos are hidden
// from the stats row, compare charts, and machine cards. Defaults to the
// most-recent combo (sorted server-side).
let indexData = null;
let activeCombo = null;

async function renderIndex() {
  try {
    indexData = await fetch("results/index.json").then((r) => r.json());
  } catch (e) {
    document.querySelector("#machines").innerHTML =
      `<p>No results yet. Run <code>uv run bench</code>, commit, push, and the
       site will populate.</p>`;
    return;
  }

  const combos = indexData.combos || [];
  // Restore last-picked combo from URL (`?leansig=<sha>&leanmultisig=<sha>`)
  // so a refresh keeps the user's selection. Falls back to most-recent combo
  // when the URL has no params; *warns* (rather than silently falling back)
  // when the URL had params but no combo matches — silent fallback can mask a
  // stale link or a deleted combo.
  const pick = comboFromUrl(combos);
  if (pick.requested && !pick.found) {
    showComboMissingWarning(pick.requested);
  }
  activeCombo = pick.found || combos[0] || null;
  renderComboFilter(combos);
  rerenderIndexForCombo();
}

function comboFromUrl(combos) {
  const params = new URLSearchParams(location.search);
  const ls = params.get("leansig");
  const lm = params.get("leanmultisig");
  if (!ls || !lm) return { requested: null, found: null };
  const found = combos.find((c) =>
    c.leansig_sha.startsWith(ls) && c.leanmultisig_sha.startsWith(lm)
  ) || null;
  return { requested: { leansig: ls, leanmultisig: lm }, found };
}

function showComboMissingWarning(requested) {
  const filter = document.querySelector("#filter");
  if (!filter || filter.querySelector(".combo-warning")) return;
  const warn = el("div", { class: "combo-warning" },
    `Requested combo (leansig ${requested.leansig} · leanmultisig ${requested.leanmultisig}) `
    + `is not in the index — showing the most-recent combo instead. Pick another from the dropdown to update the URL.`,
  );
  filter.insertBefore(warn, filter.firstChild);
}

function syncComboToUrl(combo) {
  const params = new URLSearchParams(location.search);
  if (combo) {
    // Short prefix is enough — full SHAs in URLs are noisy. We match by
    // startsWith() above, so 8 chars is safely unique within a combo set.
    params.set("leansig", shortSha(combo.leansig_sha));
    params.set("leanmultisig", shortSha(combo.leanmultisig_sha));
  } else {
    params.delete("leansig");
    params.delete("leanmultisig");
  }
  const search = params.toString();
  const url = location.pathname + (search ? "?" + search : "") + location.hash;
  history.replaceState(null, "", url);
}

function sameCombo(a, b) {
  return a && b
    && a.leansig_sha === b.leansig_sha
    && a.leanmultisig_sha === b.leanmultisig_sha;
}

function runMatchesCombo(run, combo) {
  if (!combo) return true;
  const s = run.git_shas || {};
  return s.leansig_sha === combo.leansig_sha
      && s.leanmultisig_sha === combo.leanmultisig_sha;
}

function filteredMachines(machines, combo) {
  return machines
    .map((m) => ({ ...m, runs: (m.runs || []).filter((r) => runMatchesCombo(r, combo)) }))
    .filter((m) => m.runs.length > 0);
}

function renderComboFilter(combos) {
  const details = document.querySelector("#combo-filter");
  const label   = details.querySelector(".combo-label");
  const menu    = document.querySelector("#combo-menu");

  // Click outside to close.
  document.addEventListener("click", (e) => {
    if (details.open && !details.contains(e.target)) details.open = false;
  });

  if (!combos.length) {
    label.textContent = "no runs yet";
    details.open = false;
    details.style.pointerEvents = "none";
    return;
  }

  const updateLabel = () => {
    label.textContent = comboShortLabel(activeCombo);
    details.title = `leansig ${activeCombo.leansig_sha} · leanmultisig ${activeCombo.leanmultisig_sha}`;
  };
  updateLabel();

  menu.innerHTML = "";
  for (const c of combos) {
    const active = sameCombo(c, activeCombo);
    const opt = el("div", { class: `combo-option${active ? " active" : ""}`, title:
      `leansig ${c.leansig_sha}\nleanmultisig ${c.leanmultisig_sha}` },
      el("div", { class: "combo-option-shas",
        text: `leansig ${shortSha(c.leansig_sha)} · leanmultisig ${shortSha(c.leanmultisig_sha)}` }),
      el("div", { class: "combo-option-meta",
        text: `${fmtRelative(c.latest_run_ts)} · ${c.run_count} run${c.run_count === 1 ? "" : "s"}` }),
    );
    opt.addEventListener("click", () => {
      activeCombo = c;
      details.open = false;
      updateLabel();
      for (const o of menu.querySelectorAll(".combo-option")) o.classList.remove("active");
      opt.classList.add("active");
      syncComboToUrl(c);
      // Picking a valid combo resolves the "not found" condition.
      document.querySelector(".combo-warning")?.remove();
      rerenderIndexForCombo();
    });
    menu.appendChild(opt);
  }
}

function comboShortLabel(c) {
  if (!c) return "no combo";
  return `leansig ${shortSha(c.leansig_sha)} · leanmultisig ${shortSha(c.leanmultisig_sha)}  —  ${fmtRelative(c.latest_run_ts)}`;
}

function shortSha(s) { return s && s.length >= 8 ? s.slice(0, 8) : (s || "—"); }

function rerenderIndexForCombo() {
  const machines = filteredMachines(indexData.machines || [], activeCombo);
  const runCount = machines.reduce((n, m) => n + m.runs.length, 0);

  document.querySelector("#stat-runs").textContent = runCount;
  document.querySelector("#stat-machines").textContent = machines.length;
  const latest = activeCombo ? activeCombo.latest_run_ts : indexData.generated_at;
  document.querySelector("#stat-generated").textContent = fmtDate(latest);

  const allWorkloads = new Set();
  for (const m of machines) for (const r of m.runs) for (const w of r.workloads || []) allWorkloads.add(w.name);

  const compare = document.querySelector("#compare-grid");
  compare.innerHTML = "";
  renderCompare(compare, [...allWorkloads], machines);

  const proofSizes = document.querySelector("#proof-size-grid");
  proofSizes.innerHTML = "";
  renderProofSizes(proofSizes, [...allWorkloads], machines);

  const scaling = document.querySelector("#scaling-grid");
  scaling.innerHTML = "";
  renderScaling(scaling, [...allWorkloads], machines);

  const list = document.querySelector("#machine-list");
  list.innerHTML = "";
  if (!machines.length) {
    list.appendChild(el("p", { text: "No runs match this version combo." }));
  } else {
    for (const m of machines) list.appendChild(renderMachineCard(m));
  }
}

// One chart per workload, grouped by category prefix (leansig / xmss / aggregate).
// Unknown prefixes fall into an "other" bucket so new workloads render without
// code changes.
function renderCompare(container, workloadNames, machines) {
  const grouped = {};
  for (const name of workloadNames) {
    const prefix = name.split(".")[0];
    (grouped[prefix] = grouped[prefix] || []).push(name);
  }
  for (const v of Object.values(grouped)) v.sort();

  const preferredOrder = ["leansig", "xmss", "aggregate"];
  const keys = [
    ...preferredOrder.filter((k) => grouped[k]),
    ...Object.keys(grouped).filter((k) => !preferredOrder.includes(k)).sort(),
  ];

  // Clarify which project each group belongs to. "xmss" is ambiguous
  // (leanSig also has an XMSS flavour), and "aggregate" IS leanMultisig's
  // main deliverable so it's labeled accordingly.
  const displayLabel = (g) => ({
    xmss:      "leanmultisig.xmss",
    aggregate: "leanmultisig",
  }[g] || g);

  for (const group of keys) {
    const section = el("div", { class: "compare-group" },
      el("h3", { class: "compare-group-head", text: displayLabel(group) }),
    );
    const grid = el("div", { class: "compare-group-grid" });
    for (const wl of grouped[group]) {
      grid.appendChild(buildCompareCard(wl, machines));
    }
    section.appendChild(grid);
    if (group === "aggregate") {
      section.appendChild(el("p", { class: "compare-group-note" },
        "Note: aggregate.tree timing = N × leaf + recursion. Recursion-only time below is the root node's time_secs from the per-iteration benchmark report.",
      ));
      const treeWorkloads = grouped[group].filter((n) => /\.tree_\d+x\d+_r2$/.test(n));
      if (treeWorkloads.length) {
        section.appendChild(el("h4", { class: "compare-subgroup-head",
          text: "recursion-only" }));
        const recurGrid = el("div", { class: "compare-group-grid" });
        for (const wl of treeWorkloads) {
          const card = buildRecursionCard(wl, machines);
          if (card) recurGrid.appendChild(card);
        }
        section.appendChild(recurGrid);

        // Two complementary cross-section views of the (fan-in × leaf-size)
        // grid: one fixes leaf size and varies fan-in, the other fixes
        // fan-in and varies leaf size. Each card shows machines as separate
        // lines so cross-CPU shape differences are visible at a glance.
        appendRecursionCrossSection(section, treeWorkloads, machines, "fanIn");
        appendRecursionCrossSection(section, treeWorkloads, machines, "leafSize");
      }
    }
    container.appendChild(section);
  }
}

// "aggregate.tree_NxM_r2" → derived recursion-only chart: mean tree timing
// minus N × the matching flat_M_r2 mean. Skipped per-machine if either input
// is missing; whole card is skipped if no machine has both.
function buildRecursionCard(treeName, machines) {
  const m = treeName.match(/^aggregate\.tree_(\d+)x(\d+)_r2$/);
  if (!m) return null;
  const fanIn = parseInt(m[1], 10);
  const leafSize = parseInt(m[2], 10);

  const entries = [];
  for (const [i, mach] of machines.entries()) {
    const ns = recursionRootNs(mach, treeName);
    if (ns == null) continue;
    entries.push({ label: mach.label, value: ns / 1e6, color: colorFor(i) });
  }
  if (entries.length === 0) return null;
  entries.sort((a, b) => a.value - b.value);

  const card = el("div", { class: "compare-card" });
  card.appendChild(el("h3", { text: `tree_${fanIn}x${leafSize} recursion` }));
  const wrap = el("div", { class: "compare-card-chart" });
  const canvas = el("canvas");
  wrap.appendChild(canvas);
  card.appendChild(wrap);

  const labels = entries.map((e) => e.label);
  const values = entries.map((e) => e.value);
  const colors = entries.map((e) => e.color);
  const xMax = niceCeil(Math.max(...values));

  queueMicrotask(() => {
    new Chart(canvas.getContext("2d"), {
      type: "bar",
      data: { labels, datasets: [{ data: values, backgroundColor: colors, borderRadius: 4 }] },
      options: {
        indexAxis: "y",
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          legend: { display: false },
          tooltip: {
            callbacks: {
              label: (ctx) => `${ctx.parsed.x.toFixed(3)} ms (recursion only)`,
            },
          },
        },
        scales: {
          x: { title: { display: true, text: "ms" }, beginAtZero: true, max: xMax },
          y: { ticks: { font: { family: getComputedStyle(document.body).getPropertyValue("--mono") } } },
        },
      },
    });
  });
  return card;
}

// Cross-section views of the (fan-in × leaf-size) grid. `varies` picks
// which axis is the chart's x-axis; the other axis becomes the slicer
// (one card per fixed value of it).
//
//   varies="fanIn"    → cards = leaf sizes; each card plots fan-in vs time
//   varies="leafSize" → cards = fan-ins; each card plots leaf size vs time
//
// Both produce small line charts with one line per machine.
function appendRecursionCrossSection(section, treeWorkloads, machines, varies) {
  const parsed = treeWorkloads
    .map((name) => {
      const m = name.match(/^aggregate\.tree_(\d+)x(\d+)_r2$/);
      if (!m) return null;
      return { name, fanIn: parseInt(m[1], 10), leafSize: parseInt(m[2], 10) };
    })
    .filter(Boolean);
  if (!parsed.length) return;

  const slicerKey   = varies === "fanIn" ? "leafSize" : "fanIn";
  const slicerLabel = varies === "fanIn" ? "leaf size" : "fan-in";
  const xLabel      = varies === "fanIn" ? "recursion fan-in" : "leaf size (raw XMSS sigs)";
  const headingText = varies === "fanIn"
    ? "recursion vs fan-in (per leaf size)"
    : "recursion vs leaf size (per fan-in)";

  const slicerValues = [...new Set(parsed.map((p) => p[slicerKey]))].sort((a, b) => a - b);
  if (!slicerValues.length) return;

  // First pass: build per-slicer datasets so we can share a y-axis ceiling
  // across the subgroup. With independent y-axes a small fan-in card and a
  // large fan-in card both look "flat" because each auto-zooms to its own
  // range — losing the absolute-magnitude story between cards.
  const built = [];
  for (const sv of slicerValues) {
    const row = parsed.filter((p) => p[slicerKey] === sv).sort((a, b) => a[varies] - b[varies]);
    if (row.length < 2) continue;
    const datasets = [];
    machines.forEach((mach, i) => {
      const data = row.map((p) => {
        const ns = recursionRootNs(mach, p.name);
        return ns != null ? { x: p[varies], y: ns / 1e6 } : null;
      }).filter(Boolean);
      if (data.length < 2) return;
      datasets.push({
        label: mach.label,
        data,
        borderColor: colorFor(i),
        backgroundColor: colorFor(i) + "22",
        tension: 0.15,
        fill: false,
        pointRadius: 4,
        pointHoverRadius: 6,
      });
    });
    if (!datasets.length) continue;
    built.push({ sv, row, datasets });
  }
  if (!built.length) return;

  const yMax = niceCeil(Math.max(
    ...built.flatMap((b) => b.datasets.flatMap((ds) => ds.data.map((p) => p.y))),
  ));

  const grid = el("div", { class: "compare-group-grid" });
  for (const b of built) {
    const xValues = b.row.map((p) => p[varies]);
    const card = el("div", { class: "compare-card" });
    card.appendChild(el("h3", { text: `${slicerLabel} = ${b.sv}` }));
    const wrap = el("div", { class: "compare-card-chart" });
    const canvas = el("canvas");
    wrap.appendChild(canvas);
    card.appendChild(wrap);
    grid.appendChild(card);

    queueMicrotask(() => {
      new Chart(canvas.getContext("2d"), {
        type: "line",
        data: { datasets: b.datasets },
        options: {
          responsive: true,
          maintainAspectRatio: false,
          plugins: {
            legend: { display: false },
            tooltip: {
              callbacks: {
                title: (items) => `${xLabel}: ${items[0].parsed.x}`,
                label: (ctx) => `${ctx.dataset.label}: ${ctx.parsed.y.toFixed(0)} ms`,
              },
            },
          },
          scales: {
            x: {
              type: "logarithmic",
              title: { display: true, text: xLabel },
              min: xValues[0],
              max: xValues[xValues.length - 1],
              afterBuildTicks: (axis) => {
                axis.ticks = xValues.map((v) => ({ value: v }));
              },
              ticks: { callback: (v) => v },
            },
            y: {
              title: { display: true, text: "recursion-only ms (mean)" },
              beginAtZero: true,
              max: yMax,
            },
          },
        },
      });
    });
  }
  section.appendChild(el("h4", { class: "compare-subgroup-head", text: headingText }));
  section.appendChild(grid);
}

// Proof-size section — one row per aggregate workload, showing root /
// mid / leaf KiB. Deterministic per topology, so we read off any one
// machine's run that recorded proof data. Older runs (pre-proof_kib) get
// "—" filler.
function renderProofSizes(container, workloadNames, machines) {
  const aggWorkloads = workloadNames.filter((n) => n.startsWith("aggregate.")).sort();
  if (!aggWorkloads.length) return;

  const findProof = (workloadName) => {
    for (const m of machines) {
      for (const r of m.runs || []) {
        const w = (r.workloads || []).find((x) => x.name === workloadName);
        if (w && (w.proof_kib_root != null || w.proof_kib_by_path)) return w;
      }
    }
    return null;
  };

  const rows = aggWorkloads.map((name) => {
    const w = findProof(name);
    if (!w) return { name, root: null, leaf: null, mids: [] };
    const byPath = w.proof_kib_by_path || [];
    // Group sizes by depth, average each tier (intra-tier sizes should match).
    const byDepth = {};
    for (const e of byPath) {
      (byDepth[e.depth] = byDepth[e.depth] || []).push(e.kib);
    }
    const depths = Object.keys(byDepth).map(Number).sort((a, b) => a - b);
    const avg = (xs) => Math.round(xs.reduce((a, b) => a + b, 0) / xs.length);
    const root = w.proof_kib_root ?? (byDepth[0] ? avg(byDepth[0]) : null);
    const leaf = w.proof_kib_leaf ?? (depths.length
      ? avg(byDepth[depths[depths.length - 1]])
      : null);
    // Intermediate tiers: depths strictly between 0 and the deepest leaf.
    const mids = depths.length > 2
      ? depths.slice(1, -1).map((d) => ({ depth: d, kib: avg(byDepth[d]) }))
      : [];
    return { name, root, leaf, mids };
  });

  if (rows.every((r) => r.root == null && r.leaf == null)) {
    container.appendChild(el("p", { class: "section-note",
      text: "No proof-size data in this combo yet — re-run bench with the proof_kib-capturing runner to populate." }));
    return;
  }

  const table = el("table", { class: "proof-size-table" });
  const head = el("thead");
  head.appendChild(el("tr", {},
    el("th", { text: "workload" }),
    el("th", { text: "leaf" }),
    el("th", { text: "mid" }),
    el("th", { text: "root (published)" }),
  ));
  table.appendChild(head);
  const body = el("tbody");
  for (const r of rows) {
    const fmt = (k) => k == null ? "—" : `${k} KiB`;
    const midText = r.mids.length
      ? r.mids.map((m) => `${m.kib} KiB`).join(" · ")
      : (r.leaf != null && r.root != null && r.leaf !== r.root ? "—" : "—");
    body.appendChild(el("tr", {},
      el("td", { class: "proof-size-name", text: r.name }),
      el("td", { text: fmt(r.leaf) }),
      el("td", { text: midText }),
      el("td", { class: "proof-size-root", text: fmt(r.root) }),
    ));
  }
  table.appendChild(body);
  container.appendChild(table);
}

// Scaling section — for each workload, plot timing vs physical cores across
// the c4-standard-* family. Same Granite Rapids core, only the count changes,
// so the slope is a clean read on parallel scaling for that workload.
function renderScaling(container, workloadNames, machines) {
  const c4 = machines
    .filter((m) => /^c4-standard-\d+$/.test(m.label || ""))
    .filter((m) => m.logical_cores != null)
    .sort((a, b) => a.logical_cores - b.logical_cores);

  if (c4.length < 2) {
    container.appendChild(el("p", { class: "section-note",
      text: "Need at least 2 c4-standard-* machines for a scaling line; only " + c4.length + " in this combo." }));
    return;
  }

  const grouped = {};
  for (const name of workloadNames) {
    const prefix = name.split(".")[0];
    (grouped[prefix] = grouped[prefix] || []).push(name);
  }
  for (const v of Object.values(grouped)) v.sort();

  const preferredOrder = ["leansig", "xmss", "aggregate"];
  const keys = [
    ...preferredOrder.filter((k) => grouped[k]),
    ...Object.keys(grouped).filter((k) => !preferredOrder.includes(k)).sort(),
  ];
  const displayLabel = (g) => ({ xmss: "leanmultisig.xmss", aggregate: "leanmultisig" }[g] || g);

  for (const group of keys) {
    const section = el("div", { class: "compare-group" },
      el("h3", { class: "compare-group-head", text: displayLabel(group) }),
    );
    const grid = el("div", { class: "compare-group-grid" });
    for (const wl of grouped[group]) {
      const card = buildScalingCard(wl, c4);
      if (card) grid.appendChild(card);
    }
    section.appendChild(grid);
    if (group === "aggregate") {
      const treeWorkloads = grouped[group].filter((n) => /\.tree_\d+x\d+_r2$/.test(n));
      if (treeWorkloads.length) {
        section.appendChild(el("h4", { class: "compare-subgroup-head",
          text: "recursion-only" }));
        // Pre-compute every recursion line's points so all charts in this
        // subgroup share a y-axis ceiling — at-a-glance comparison across
        // tree variants needs a common scale.
        const built = treeWorkloads.map((wl) => ({
          name: wl,
          points: recursionScalingPoints(wl, c4),
        })).filter((b) => b.points && b.points.length >= 2);
        const yMax = niceCeil(Math.max(...built.flatMap((b) => b.points.map((p) => p.y))));
        const recurGrid = el("div", { class: "compare-group-grid" });
        for (const b of built) {
          recurGrid.appendChild(buildRecursionScalingCard(b.name, b.points, yMax));
        }
        section.appendChild(recurGrid);
      }
    }
    container.appendChild(section);
  }
}

// Returns the best (smallest mean) recursion-only time in ns for a given
// tree workload on a machine, read directly off the root node's `time_secs`
// in the runner's per-iteration reports. Returns null when the machine has
// no run with raw report data — older runs without `time_ns_root` simply
// don't render in the recursion-only chart (no derivation fallback; the
// derived form `tree − N × flat` double-counts per-call setup overhead and
// gives a noisier, slightly biased number).
function recursionRootNs(machine, treeName) {
  let best = null;
  for (const r of machine.runs || []) {
    const w = (r.workloads || []).find((x) => x.name === treeName);
    if (w && w.time_ns_root != null && (best == null || w.time_ns_root < best)) {
      best = w.time_ns_root;
    }
  }
  return best;
}

function recursionScalingPoints(treeName, c4Machines) {
  const points = [];
  for (const mach of c4Machines) {
    const ns = recursionRootNs(mach, treeName);
    if (ns == null) continue;
    points.push({ x: mach.logical_cores, y: ns / 1e6 });
  }
  return points;
}

function buildRecursionScalingCard(treeName, points, yMax) {
  const m = treeName.match(/^aggregate\.tree_(\d+)x(\d+)_r2$/);
  const fanIn = parseInt(m[1], 10);
  const leafSize = parseInt(m[2], 10);

  const card = el("div", { class: "compare-card" });
  card.appendChild(el("h3", { text: `tree_${fanIn}x${leafSize} recursion` }));
  const wrap = el("div", { class: "compare-card-chart" });
  const canvas = el("canvas");
  wrap.appendChild(canvas);
  card.appendChild(wrap);

  queueMicrotask(() => {
    new Chart(canvas.getContext("2d"), {
      type: "line",
      data: {
        datasets: [{
          data: points,
          borderColor: "#4a46d9",
          backgroundColor: "#4a46d922",
          pointRadius: 4,
          pointHoverRadius: 6,
          tension: 0.15,
          fill: false,
        }],
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          legend: { display: false },
          tooltip: {
            callbacks: {
              title: (items) => `${items[0].parsed.x} logical cores`,
              label: (ctx) => `${ctx.parsed.y.toFixed(3)} ms (recursion only)`,
            },
          },
        },
        scales: {
          x: {
            type: "logarithmic",
            title: { display: true, text: "logical cores (vCPU)" },
            min: points[0].x,
            max: points[points.length - 1].x,
            afterBuildTicks: (axis) => {
              axis.ticks = points.map((p) => ({ value: p.x }));
            },
            ticks: { callback: (v) => v },
          },
          y: {
            title: { display: true, text: "ms (mean)" },
            beginAtZero: true,
            max: yMax,
          },
        },
      },
    });
  });
  return card;
}

function buildScalingCard(workloadName, c4Machines) {
  const points = [];
  for (const m of c4Machines) {
    let best = null;
    for (const r of m.runs || []) {
      const w = (r.workloads || []).find((x) => x.name === workloadName);
      if (w && w.mean_ns != null && (best == null || w.mean_ns < best)) best = w.mean_ns;
    }
    if (best != null) points.push({ x: m.logical_cores, y: best / 1e6 });
  }
  if (points.length < 2) return null;

  const card = el("div", { class: "compare-card" });
  card.appendChild(el("h3", { text: workloadName }));
  const wrap = el("div", { class: "compare-card-chart" });
  const canvas = el("canvas");
  wrap.appendChild(canvas);
  card.appendChild(wrap);

  // log2 spacing for cores (2,4,8,16 land on integer ticks); keep
  // ms axis linear so the eye reads timing differences directly.
  queueMicrotask(() => {
    new Chart(canvas.getContext("2d"), {
      type: "line",
      data: {
        datasets: [{
          data: points,
          borderColor: "#4a46d9",
          backgroundColor: "#4a46d922",
          pointRadius: 4,
          pointHoverRadius: 6,
          tension: 0.15,
          fill: false,
        }],
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          legend: { display: false },
          tooltip: {
            callbacks: {
              title: (items) => `${items[0].parsed.x} logical cores`,
              label: (ctx) => `${ctx.parsed.y.toFixed(3)} ms`,
            },
          },
        },
        scales: {
          x: {
            type: "logarithmic",
            title: { display: true, text: "logical cores (vCPU)" },
            min: points[0].x,
            max: points[points.length - 1].x,
            // Chart.js's default log ticks are decade-based (4,5,…,9,10,20,30),
            // so 16 never lands as a candidate. Replace the tick set with
            // exactly the data-point values so each c4 size gets its own label.
            afterBuildTicks: (axis) => {
              axis.ticks = points.map((p) => ({ value: p.x }));
            },
            ticks: { callback: (v) => v },
          },
          y: { title: { display: true, text: "ms (mean)" }, beginAtZero: true },
        },
      },
    });
  });
  return card;
}

function buildCompareCard(workloadName, machines) {
  const card = el("div", { class: "compare-card" });
  card.appendChild(el("h3", { text: workloadName }));
  const wrap = el("div", { class: "compare-card-chart" });
  const canvas = el("canvas");
  wrap.appendChild(canvas);
  card.appendChild(wrap);

  // Build per-machine entries first, THEN sort by speed (fastest first).
  // Color is bound to the machine's original list index so the same machine
  // keeps the same color across charts — only the ordering changes per chart.
  // Capture p5 + p95 alongside mean from the same "best run" so whiskers
  // correspond to that specific run, not a mix.
  const entries = [];
  for (const [i, m] of machines.entries()) {
    let best = null;
    let bestP5 = null;
    let bestP95 = null;
    for (const r of m.runs || []) {
      const w = (r.workloads || []).find((x) => x.name === workloadName);
      if (w && w.mean_ns != null && (best == null || w.mean_ns < best)) {
        best = w.mean_ns;
        bestP5 = w.p5_ns ?? null;
        bestP95 = w.p95_ns ?? null;
      }
    }
    if (best != null) {
      entries.push({
        label: m.label,
        value: best / 1e6,
        p5:  bestP5  != null ? bestP5  / 1e6 : null,
        p95: bestP95 != null ? bestP95 / 1e6 : null,
        color: colorFor(i),
      });
    }
  }
  entries.sort((a, b) => a.value - b.value);
  const labels = entries.map((e) => e.label);
  const values = entries.map((e) => e.value);
  const p5Values = entries.map((e) => e.p5);
  const p95Values = entries.map((e) => e.p95);
  const colors = entries.map((e) => e.color);

  // Force the x-axis to extend past the longest right whisker so p95 caps
  // never get clipped, and round up to a "nice" multiple of 1/2/2.5/5×10^k
  // so the axis ticks land on readable numbers (12 → 15, 377 → 400, etc.).
  const maxRight = Math.max(
    ...values,
    ...p95Values.filter((v) => v != null),
  );
  const xMax = niceCeil(maxRight);

  queueMicrotask(() => {
    new Chart(canvas.getContext("2d"), {
      type: "bar",
      data: {
        labels,
        datasets: [{
          data: values,
          backgroundColor: colors,
          borderRadius: 4,
          p5: p5Values,
          p95: p95Values,
        }],
      },
      options: {
        indexAxis: "y",
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          legend: { display: false },
          tooltip: {
            callbacks: {
              // Multi-line tooltip — first line is the headline mean, then
              // p5/p95 only if we have them. Returning an array gives us
              // one DOM line per element.
              label: (ctx) => {
                const out = [`mean   ${ctx.parsed.x.toFixed(3)} ms  (best run)`];
                const p5 = p5Values[ctx.dataIndex];
                const p95 = p95Values[ctx.dataIndex];
                if (p5  != null) out.unshift(`p5     ${p5.toFixed(3)} ms`);
                if (p95 != null) out.push(`p95    ${p95.toFixed(3)} ms`);
                return out;
              },
            },
          },
        },
        scales: {
          x: { title: { display: true, text: "ms" }, beginAtZero: true, max: xMax },
          y: { ticks: { font: { family: getComputedStyle(document.body).getPropertyValue("--mono") } } },
        },
      },
      plugins: [variancePlugin],
    });
  });
  return card;
}

// Draws a horizontal whisker on each bar — leftward from p5 to mean, and
// rightward from mean to p95, each with a small cap. Lives outside per-
// chart code so it's registered once per Chart instance via `plugins:`.
// p5 / p95 values are passed in via `dataset.p5` and `dataset.p95`.
const variancePlugin = {
  id: "variance",
  afterDatasetDraw(chart, args) {
    const { ctx } = chart;
    const meta = chart.getDatasetMeta(args.index);
    const dataset = chart.data.datasets[args.index];
    const p5s  = dataset.p5;
    const p95s = dataset.p95;
    if (!Array.isArray(p5s) && !Array.isArray(p95s)) return;

    const dark = matchMedia("(prefers-color-scheme: dark)").matches;
    ctx.save();
    ctx.lineCap = "round";
    ctx.lineWidth = 1;
    ctx.strokeStyle = dark ? "rgba(240, 240, 234, 0.85)" : "rgba(26, 26, 26, 0.75)";

    const drawSegment = (x1, x2, y, cap) => {
      ctx.beginPath();
      ctx.moveTo(x1, y);
      ctx.lineTo(x2, y);
      ctx.moveTo(x2, y - cap);
      ctx.lineTo(x2, y + cap);
      ctx.stroke();
    };

    meta.data.forEach((bar, i) => {
      const meanX = bar.x;
      const y = bar.y;
      const cap = Math.min(7, (bar.height ?? 12) * 0.4);

      // Right whisker: mean → p95 (lives on chart background)
      const p95 = (p95s || [])[i];
      if (p95 != null) {
        const p95X = chart.scales.x.getPixelForValue(p95);
        if (p95X > meanX) drawSegment(meanX, p95X, y, cap);
      }

      // Left whisker: p5 → mean (lives on top of the colored bar fill)
      const p5 = (p5s || [])[i];
      if (p5 != null) {
        const p5X = chart.scales.x.getPixelForValue(p5);
        if (p5X < meanX) drawSegment(meanX, p5X, y, cap);
      }
    });

    ctx.restore();
  },
};

// Approximate on-demand list price (USD/hour) for the GCP machine types
// in the default remote-bench matrix, us-central1, as of 2026-04. Used
// only for a "≈$N/mo" hint on machine cards — not sustained-use or
// committed-use discounted, so treat as upper bound. Local machines (no
// matching key) get no cost shown.
const GCP_USD_PER_HOUR = {
  "n1-standard-4":   0.190,
  "c4-standard-4":   0.210,
  "c4-standard-8":   0.420,
  "c4-standard-16":  0.840,
  "c4-standard-32":  1.680,
};
const HOURS_PER_MONTH = 730;

const fmtMonthly = (label) => {
  const hourly = GCP_USD_PER_HOUR[label];
  if (hourly == null) return null;
  const monthly = Math.round(hourly * HOURS_PER_MONTH);
  return {
    short: `≈$${monthly.toLocaleString()}/mo`,
    title: `GCP ${label} · us-central1 on-demand · $${hourly.toFixed(3)}/hr × ${HOURS_PER_MONTH} h ≈ $${monthly}/mo (no SUD/CUD applied)`,
  };
};

function renderMachineCard(m) {
  const card = el("div", { class: "machine-card" });
  const cost = fmtMonthly(m.label);
  const metaText = `${m.cpu_model || ""} · ${m.physical_cores ?? "?"}p / ${m.logical_cores ?? "?"}l · ${m.memory_gb ?? "?"} GB · ${m.os || ""}`;
  const meta = el("div", { class: "machine-meta" }, metaText);
  if (cost) {
    meta.appendChild(document.createTextNode(" · "));
    meta.appendChild(el("span", { class: "machine-cost", title: cost.title, text: cost.short }));
  }
  card.appendChild(el("div", { class: "machine-head" },
    el("h3", { text: m.label || m.fingerprint }),
    meta,
  ));
  const runs = el("div", { class: "run-list" });
  for (const r of m.runs || []) {
    const link = el("a", {
      class: "run-item",
      href: `run.html?file=${encodeURIComponent(r.file)}`,
    },
      el("div", { class: "run-ts", text: fmtDate(r.timestamp) }),
      el("div", { text: `${(r.workloads || []).length} workload(s)` }),
    );
    runs.appendChild(link);
  }
  card.appendChild(runs);
  return card;
}

// ---------- RUN detail page -------------------------------------------------

async function renderRun() {
  const params = new URLSearchParams(location.search);
  const file = params.get("file");
  if (!file) {
    document.querySelector("#run-title").textContent = "no run selected";
    return;
  }

  const rawHref = `results/${file}`;
  document.querySelector("#raw-link").href = rawHref;

  let rec;
  try {
    rec = await fetch(rawHref).then((r) => r.json());
  } catch (e) {
    document.querySelector("#run-title").textContent = "failed to load";
    return;
  }

  document.querySelector("#run-title").textContent = rec.machine?.label || rec.run_id;
  document.querySelector("#run-subtitle").textContent =
    `${fmtDate(rec.timestamp)} · schema v${rec.schema_version ?? "?"}`;

  const spec = document.querySelector("#spec-grid");
  spec.className = "grid";
  const m = rec.machine || {};
  for (const [k, v] of [
    ["CPU", m.cpu_model],
    ["Arch", m.cpu_arch],
    ["Cores", `${m.physical_cores ?? "?"} physical / ${m.logical_cores ?? "?"} logical`],
    ["Memory", `${m.memory_gb ?? "?"} GB`],
    ["OS", m.os],
    ["Kernel", m.kernel],
    ["Fingerprint", m.fingerprint],
  ]) {
    if (v == null) continue;
    spec.appendChild(el("dt", { text: k }));
    spec.appendChild(el("dd", { text: String(v) }));
  }

  const prov = document.querySelector("#prov-grid");
  prov.className = "grid";
  const t = rec.toolchain || {};
  // GitHub `tree/<sha>` shows the working dir at that commit — better than
  // `commit/<sha>` which shows just the diff. Both SHAs are pinned to the
  // upstream leanEthereum repos via runner-rust/Cargo.toml.
  const treeBase = (repo) => `https://github.com/leanEthereum/${repo}/tree/`;
  const provEntries = [
    ["rustc",            t.rustc, null],
    ["leanSig SHA",      t.git_shas?.leansig_sha,      treeBase("leanSig")],
    ["leanMultisig SHA", t.git_shas?.leanmultisig_sha, treeBase("leanMultisig")],
    ["Run ID",           rec.run_id, null],
    ["Notes",            rec.notes, null],
  ];
  for (const [k, v, urlBase] of provEntries) {
    if (!v) continue;
    prov.appendChild(el("dt", { text: k }));
    if (urlBase && /^[0-9a-f]{7,40}$/i.test(String(v))) {
      const dd = el("dd");
      dd.appendChild(el("a", {
        href: urlBase + v,
        target: "_blank",
        rel: "noopener noreferrer",
        text: String(v),
      }));
      prov.appendChild(dd);
    } else {
      prov.appendChild(el("dd", { text: String(v) }));
    }
  }

  const list = document.querySelector("#workload-list");
  for (const [i, w] of (rec.workloads || []).entries()) {
    list.appendChild(renderWorkload(w, i));
  }
}

function renderWorkload(w, idx) {
  const card = el("div", { class: "workload" });
  const t = w.timing || {};
  card.appendChild(el("div", { class: "workload-head" },
    el("h3", { class: "workload-name", text: w.name || "?" }),
    el("div", { class: "workload-headline", text: fmtNs(t.mean_ns) }),
  ));

  const stats = el("div", { class: "workload-stats" });
  for (const [label, value] of [
    ["n",      t.n],
    ["min",    fmtNs(t.min_ns)],
    ["p50",    fmtNs(t.p50_ns)],
    ["mean",   fmtNs(t.mean_ns)],
    ["p95",    fmtNs(t.p95_ns)],
    ["max",    fmtNs(t.max_ns)],
    ["stddev", fmtNs(t.stddev_ns)],
  ]) {
    if (value == null) continue;
    stats.appendChild(el("div", { class: "workload-stat" },
      el("div", { class: "workload-stat-label", text: label }),
      el("div", { class: "workload-stat-value", text: String(value) }),
    ));
  }
  // Resources (CPU / RSS)
  const res = w.resources || {};
  if (res.cpu_percent) {
    stats.appendChild(el("div", { class: "workload-stat" },
      el("div", { class: "workload-stat-label", text: "cpu peak" }),
      el("div", { class: "workload-stat-value", text: `${res.cpu_percent.peak?.toFixed?.(0) ?? res.cpu_percent.peak}%` }),
    ));
  }
  if (res.rss_bytes) {
    stats.appendChild(el("div", { class: "workload-stat" },
      el("div", { class: "workload-stat-label", text: "rss peak" }),
      el("div", { class: "workload-stat-value", text: fmtBytes(res.rss_bytes.peak) }),
    ));
  }
  card.appendChild(stats);

  if (Array.isArray(w.samples_ns) && w.samples_ns.length > 1) {
    const wrap = el("div", { class: "workload-chart-wrap" });
    const canvas = el("canvas");
    wrap.appendChild(canvas);
    card.appendChild(wrap);

    queueMicrotask(() => {
      new Chart(canvas.getContext("2d"), {
        type: "line",
        data: {
          labels: w.samples_ns.map((_, i) => i + 1),
          datasets: [{
            label: "sample (ms)",
            data: w.samples_ns.map((ns) => ns / 1e6),
            borderColor: colorFor(idx),
            backgroundColor: colorFor(idx) + "22",
            pointRadius: 2,
            tension: 0.15,
            fill: true,
          }],
        },
        options: {
          responsive: true,
          maintainAspectRatio: false,
          plugins: { legend: { display: false } },
          scales: {
            x: { title: { display: true, text: "sample" } },
            y: { title: { display: true, text: "ms" }, beginAtZero: false },
          },
        },
      });
    });
  }

  if (w.meta && Object.keys(w.meta).length) {
    const metaRow = el("div", { class: "workload-meta" });
    for (const [k, v] of Object.entries(w.meta)) {
      metaRow.appendChild(el("span", { text: `${k}=${typeof v === "object" ? JSON.stringify(v) : v}` }));
    }
    card.appendChild(metaRow);
  }

  return card;
}

// ---------- dispatch --------------------------------------------------------

if (page === "run") renderRun();
else renderIndex();
